import { useContext } from 'react';

import type { Formatter } from '../../../../../types/formatter.js';
import { getFormatter } from '../../../../../utils/get-formatter.js';
import { AnnotationsTooltipFormatterContext } from '../contexts/AnnotationsTooltipFormatter.context.js';

export const useAnnotationsTooltipFormatter = (): Formatter => {
  const contextFormatter = useContext(AnnotationsTooltipFormatterContext);

  return getFormatter(contextFormatter);
};
